import time
import datetime
from flask import Flask
app = Flask(__name__)

class Solution:
  def home(self):
    def before_request():
      res = datetime.datetime.now()
      endTime = datetime.datetime.now()
      if endTime - res > datetime.timedelta(milliseconds=1000):
        return "Too slow"
      else:
        return f"Request took \{endTime-res}ms"

    @app.before_request
    def _before_request():
      return before_request()

    @app.route('/', methods=['GET'])
def _home():
      return "Hello World!"

    return _home()

if __name__ == '__main__':
  app.run(debug=True)
  print('Server running...')
